// src/components/home.jsx
import React, { useEffect, useState, useRef } from "react";
import "../styles/home.css";
import { Link } from "react-router-dom";
import axios from "axios";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8000";

export default function Home({ rooms: initialRooms = [], photos = [] }) {
  const [index, setIndex] = useState(1);
  const slideCount = 3;
  const autoPlayRef = useRef(null);

  const [rooms, setRooms] = useState([]);
  const [loadingRooms, setLoadingRooms] = useState(false);
  const [roomsError, setRoomsError] = useState("");

  /* ---------------- SLIDER AUTO PLAY ---------------- */
  useEffect(() => {
    autoPlayRef.current = setInterval(() => {
      setIndex((i) => (i >= slideCount ? 1 : i + 1));
    }, 6000);
    return () => clearInterval(autoPlayRef.current);
  }, []);

  /* ---------------- FADE-IN OBSERVER ---------------- */
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((e) => e.isIntersecting && e.target.classList.add("show"));
      },
      { threshold: 0.1 }
    );

    document
      .querySelectorAll(".fade-in, .fade-up, .fade-left, .fade-right")
      .forEach((el) => {
        if (!el.closest(".hero-wrap") && !el.closest(".nav")) {
          observer.observe(el);
        }
      });

    return () => observer.disconnect();
  }, []);

  /* ---------------- FETCH ROOMS ---------------- */
  useEffect(() => {
    if (Array.isArray(initialRooms) && initialRooms.length > 0) {
      setRooms(initialRooms.map(normalizeRoom));
    } else {
      fetchRooms();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  async function fetchRooms() {
    setLoadingRooms(true);
    setRoomsError("");
    try {
      const res = await axios.get(`${API_BASE}/api/rooms/`);
      const data = Array.isArray(res.data) ? res.data : res.data.results || [];
      setRooms(data.map(normalizeRoom));
    } catch (err) {
      console.error(err);
      setRoomsError("Unable to load rooms.");
    } finally {
      setLoadingRooms(false);
    }
  }

  /* ---------------- NORMALIZE ROOM ---------------- */
  function normalizeRoom(r) {
    const extractSrc = (img) => {
      if (!img) return null;
      if (typeof img === "string") return img;
      if (typeof img === "object")
        return img.url || img.image || img.image_path || img.path || null;
      return null;
    };

    const imgs = r.images || r.room_images || [];
    let preview = imgs.length ? extractSrc(imgs[0]) : null;
    if (!preview) preview = extractSrc(r.image || r.image_path);

    let image = "/assets/images/uploads/default.jpg";
    if (preview) {
      image = preview.startsWith("http")
        ? preview
        : `${API_BASE}${preview.startsWith("/") ? preview : "/" + preview}`;
    }

    return {
      id: r.id,
      room_id: r.id,
      room_name: r.room_name,
      capacity: r.capacity,
      price: r.price,
      image,
    };
  }

  /* ---------------- SLIDER HELPERS ---------------- */
  const slideBackground = (n) => ({
    backgroundImage: `url('/assets/images/glamp${n}.jpg')`,
  });
  const goPrev = () => setIndex((i) => (i <= 1 ? slideCount : i - 1));
  const goNext = () => setIndex((i) => (i >= slideCount ? 1 : i + 1));

  return (
    <div id="app">
      {/* ================= SLIDER ================= */}
      <div className="slider">
        {[1, 2, 3].map((n) => (
          <div
            key={n}
            className={`slide slide-${n} ${index === n ? "active" : ""}`}
            style={slideBackground(n)}
          />
        ))}

        <header className="nav">
          <div className="nav-inner">
            <img src="/assets/images/glamp_logo.png" className="logo" alt="logo" />
            <nav className="menu">
              <a href="/">Home</a>
              <a href="#rooms">Rooms</a>
              <Link to="/reservation">Reservation</Link>
              <a className="reserve" href="/reservation">RESERVATION</a>
            </nav>
          </div>
        </header>

        <div className="arrow left" onClick={goPrev}><button>‹</button></div>
        <div className="arrow right" onClick={goNext}><button>›</button></div>
      </div>

      {/* ================= ACCOMMODATION ================= */}
      <section className="accommodation fade-up" id="rooms">
        <div className="accommodation-inner">
          <div className="section-title">
            <span className="subtitle">ELEGANT</span>
            <h2>Accommodation</h2>
          </div>

          {loadingRooms ? (
            <p>Loading rooms...</p>
          ) : rooms.length > 0 ? (
            <div className="rooms-grid">
              {rooms.map((room) => (
                <div className="room-card fade-up" key={room.id}>
                  <div className="arch-img">
                    <img src={room.image} alt={room.room_name} />
                    <div className="room-info">
                      <h3>{room.room_name}</h3>
                      <p>{room.capacity} Guests</p>
                    </div>
                    <div className="overlay">
                      <span className="price">
                        From ₹{Number(room.price).toFixed(2)}
                      </span>
                      <Link to={`/room/${room.id}`} className="details-btn">
                        View Details
                      </Link>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <p>No rooms available.</p>
          )}

          {roomsError && <p style={{ color: "red" }}>{roomsError}</p>}
        </div>
      </section>
    </div>
  );
}
